module signal_generator(
    input clk,
    input rst_n,
    output reg [4:0] wave
);

    reg up;

    always @(posedge clk or negedge rst_n) begin
        if (!rst_n) begin
            wave <= 5'b00000;
            up <= 1'b1;
        end
        else begin
            if (up) begin
                if (wave == 5'b11110) begin
                    up <= 1'b0;
                    wave <= wave - 1;
                end
                else begin
                    wave <= wave + 1;
                end
            end
            else begin
                if (wave == 5'b00001) begin
                    up <= 1'b1;
                    wave <= wave + 1;
                end
                else begin
                    wave <= wave - 1;
                end
            end
        end
    end

endmodule
